{"code":"import json
import re

try:
    with open(locals()['var_function-call-17216969929108140412'], 'r') as f:
        papers = json.load(f)
except:
    papers = []

titles = []

# Regex for strict header year
regex_2016 = re.compile(r"(?:Copyright|©).{0,50}2016|(?:CHI|UbiComp|CSCW|DIS|PervasiveHealth|WWW|IUI|OzCHI|TEI|AH).{0,50}(?:2016|'16)|(?:January|February|March|April|May|June|July|August|September|October|November|December).{0,50}2016", re.IGNORECASE)

for p in papers:
    text = p.get('text', '')
    header = text[:2000] # Check first 2000 chars for safety

    # Check if published in 2016
    if regex_2016.search(header):
        # Double check it's not 2015/2017 overriding
        if re.search(r"(?:Copyright|©).{0,50}(?:2015|2014|2017|2018)", header, re.IGNORECASE) and not re.search(r"(?:Copyright|©).{0,50}2016", header, re.IGNORECASE):
             continue

        # Check domain
        if 'physical activity' in text.lower():
            titles.append(p.get('filename').replace('.txt', ''))

print("__RESULT__:")
print(json.dumps(titles))"}

