{"code":"import json
import re

try:
    with open(locals()['var_function-call-18233020040394176288'], 'r') as f:
        papers = json.load(f)
except:
    papers = []

titles_2016 = []

# Regex for 2016 publication. 
# Matches: "Copyright 2016", "Copyright (c) 2016", "© 2016", "CHI 2016", "Ubicomp '16"
regex_2016 = re.compile(r"(?:Copyright|©).{0,20}2016|(?:CHI|UbiComp|CSCW|DIS|PervasiveHealth|WWW|IUI|OzCHI|TEI|AH).{0,20}(?:2016|'16)", re.IGNORECASE)

for p in papers:
    text = p.get('text', '')
    header = text[:2000] # Increased header size

    # Check domain (already filtered by Mongo query, but good to double check)
    if 'physical activity' not in text.lower():
        continue

    # Check year
    if regex_2016.search(header):
        # Exclude if explicit other year found in copyright
        if re.search(r"(?:Copyright|©).{0,20}(?:2015|2014|2017|2018)", header, re.IGNORECASE):
             if not re.search(r"(?:Copyright|©).{0,20}2016", header, re.IGNORECASE):
                 continue

        titles_2016.append(p.get('filename').replace('.txt', ''))

print("__RESULT__:")
print(json.dumps(titles_2016))"}

{"code":"import json
import re

try:
    with open(locals()['var_function-call-5276622005229675102'], 'r') as f:
        papers = json.load(f)
except:
    papers = []

